  try {
    // Validate query parameters if any
    const { limit = 10, offset = 0 } = req.query;

    // Input validation
    if (!Number.isInteger(parseInt(limit)) || parseInt(limit) < 1 || parseInt(limit) > 100) {
      return res.status(400).json({ error: 'Invalid limit parameter' });
    }

    if (!Number.isInteger(parseInt(offset)) || parseInt(offset) < 0) {
      return res.status(400).json({ error: 'Invalid offset parameter' });
    }

    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    // Apply pagination safely
    const paginatedUsers = users.slice(parseInt(offset), parseInt(offset) + parseInt(limit));

    res.json({
      data: paginatedUsers,
      total: users.length,
      limit: parseInt(limit),
      offset: parseInt(offset)
    });
  } catch (error) {
    console.error('Users endpoint error:', error);
    res.status(500).json({ error: 'Internal server error' });
  }
});

// 404 handler
app.use((req, res) => {
  res.status(404).json({ error: 'Endpoint not found' });
});

// Global error handler (must be last)
app.use((err, req, res, next) => {
  console.error('Unhandled error:', err);

  // Don't expose internal error details in production
  const isDevelopment = process.env.NODE_ENV === 'development';

  res.status(err.status || 500).json({
    error: 'Internal server error',
    ...(isDevelopment && { message: err.message, stack: err.stack })
  });
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

module.exports = app;
```

