// Enhanced app.js with security best practices
const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const validator = require('validator');
const app = express();

// ===== SECURITY MIDDLEWARE =====

// 1. Helmet.js - Set various HTTP headers for security
app.use(helmet());

// 2. Rate limiting - Prevent brute force and DoS attacks
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // limit each IP to 100 requests per windowMs
  message: 'Too many requests from this IP, please try again later.',
  standardHeaders: true,
  legacyHeaders: false,
});
app.use(limiter);

// 3. Body parser with size limits
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ limit: '10kb', extended: true }));

// 4. CORS - Restrict cross-origin requests
const cors = require('cors');
app.use(cors({
  origin: process.env.ALLOWED_ORIGINS?.split(',') || 'http://localhost:3000',
  credentials: true,
  methods: ['GET', 'POST'],
  allowedHeaders: ['Content-Type', 'Authorization'],
}));

// 5. Request logging middleware
app.use((req, res, next) => {
  const timestamp = new Date().toISOString();
  console.log(`[${timestamp}] ${req.method} ${req.path}`);
  next();
});

// ===== ROUTES =====

// Health check endpoint (public, minimal info)
app.get('/health', (req, res) => {
  try {
    res.json({ status: 'ok', timestamp: new Date().toISOString() });
  } catch (error) {
    console.error('Health check error:', error);
    res.status(500).json({ status: 'error', message: 'Internal server error' });
  }
});

// Users endpoint with security improvements
app.get('/users', (req, res) => {
  try {
    // Input validation for query parameters
    const { id, limit, offset } = req.query;

    // Validate optional filters
    if (id && (!validator.isInt(id, { min: 1 }))) {
      return res.status(400).json({ 
        error: 'Invalid id parameter. Must be a positive integer.' 
      });
    }

    if (limit && !validator.isInt(limit, { min: 1, max: 100 })) {
      return res.status(400).json({ 
        error: 'Invalid limit parameter. Must be between 1 and 100.' 
      });
    }

    if (offset && !validator.isInt(offset, { min: 0 })) {
      return res.status(400).json({ 
        error: 'Invalid offset parameter. Must be a non-negative integer.' 
      });
    }

    // Sample data - in production, this would be from a database
    const allUsers = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    // Apply filters
    let result = allUsers;
    if (id) {
      result = result.filter(u => u.id === parseInt(id, 10));
    }

    // Pagination
    const pageLimit = Math.min(parseInt(limit, 10) || 10, 100);
    const pageOffset = parseInt(offset, 10) || 0;
    result = result.slice(pageOffset, pageOffset + pageLimit);

    res.json({
      data: result,
      pagination: { limit: pageLimit, offset: pageOffset },
    });
  } catch (error) {
    console.error('Users endpoint error:', error);
    // Don't leak stack trace to client
    res.status(500).json({ error: 'Failed to retrieve users' });
  }
});

// ===== ERROR HANDLING =====

// 404 handler
app.use((req, res) => {
  res.status(404).json({ error: 'Route not found' });
});

// Global error handler
app.use((err, req, res, next) => {
  console.error('Unhandled error:', err);

  // Don't expose internal error details in production
  const isDevelopment = process.env.NODE_ENV === 'development';
  const message = isDevelopment ? err.message : 'Internal server error';

  res.status(err.status || 500).json({
    error: message,
    ...(isDevelopment && { stack: err.stack }),
  });
});

// ===== SERVER START =====

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

module.exports = app;
